<script setup lang="ts">
import { computed, onMounted, reactive, ref } from "vue"
import { useRoute, useRouter } from "vue-router"
import draggable from "vuedraggable"
import { ArrowLeft, GripVertical, Plus, Trash2, Upload } from "lucide-vue-next"
import { NButton, NCard, NForm, NFormItem, NInput, NInputNumber, NModal, NProgress, NSelect, NSpace, NSwitch } from "naive-ui"
import StatusTag from "@/components/common/StatusTag.vue"
import ErrorState from "@/components/common/ErrorState.vue"
import { feedback } from "@/lib/feedback"
import { fmtDateTime, slugify } from "@/lib/format"
import { lessonsApi, type CourseDetail, type CourseLevel, type Episode, type EpisodeContentType } from "@/lib/api/lessons"

const route = useRoute(); const router = useRouter(); const isNew = computed(() => !route.params.id)
const course = ref<CourseDetail | null>(null); const episodes = ref<Episode[]>([]); const loading = ref(false); const saving = ref(false); const error = ref<string | null>(null)
const uploadProgress = ref<number | null>(null); const episodeModal = ref(false); const editingEpisode = ref<Episode | null>(null)
const form = reactive({ title: "", slug: "", description: "", level: "beginner" as CourseLevel, category: "", isPremium: false, isPublished: false })
const episodeForm = reactive({ title: "", description: "", contentType: "text" as EpisodeContentType, markdownBody: "", sortOrder: 1, isPublished: false })
const levelOptions = ["beginner", "intermediate", "advanced"].map((value) => ({ label: value, value }))
const contentOptions = ["text", "pdf", "video"].map((value) => ({ label: value, value }))

async function load() {
  if (isNew.value) return
  loading.value = true; error.value = null
  try {
    const data = await lessonsApi.get(String(route.params.id)); course.value = data; episodes.value = [...data.episodes].sort((a, b) => a.sortOrder - b.sortOrder); Object.assign(form, { title: data.title, slug: data.slug, description: data.description ?? "", level: data.level, category: data.category, isPremium: data.isPremium, isPublished: data.isPublished })
  } catch (err) { error.value = err instanceof Error ? err.message : "Không thể tải khoá học" } finally { loading.value = false }
}
function syncSlug() { if (isNew.value) form.slug = slugify(form.title) }
async function saveCourse() {
  saving.value = true
  try {
    if (isNew.value) { const created = await lessonsApi.create({ slug: form.slug, title: form.title, description: form.description || undefined, level: form.level, category: form.category, isPremium: form.isPremium }); feedback.message?.success("Đã tạo khoá học"); await router.replace(`/lessons/${created.id}`) }
    else { course.value = await lessonsApi.update(String(route.params.id), { slug: form.slug, title: form.title, description: form.description || undefined, level: form.level, category: form.category, isPremium: form.isPremium, isPublished: form.isPublished }); feedback.message?.success("Đã lưu khoá học") }
  } catch (err) { feedback.message?.error(err instanceof Error ? err.message : "Lưu thất bại") } finally { saving.value = false }
}
function openEpisode(ep?: Episode) { editingEpisode.value = ep ?? null; Object.assign(episodeForm, ep ? { title: ep.title, description: ep.description ?? "", contentType: ep.contentType, markdownBody: ep.markdownBody ?? "", sortOrder: ep.sortOrder, isPublished: ep.isPublished } : { title: "", description: "", contentType: "text", markdownBody: "", sortOrder: episodes.value.length + 1, isPublished: false }); episodeModal.value = true }
async function saveEpisode() { if (!course.value) return; const payload = { title: episodeForm.title, description: episodeForm.description || undefined, contentType: episodeForm.contentType, markdownBody: episodeForm.markdownBody || undefined, sortOrder: episodeForm.sortOrder }; const ep = editingEpisode.value ? await lessonsApi.updateEpisode(editingEpisode.value.id, { ...payload, isPublished: episodeForm.isPublished }) : await lessonsApi.createEpisode(course.value.id, payload); upsertEpisode(ep); episodeModal.value = false; feedback.message?.success("Đã lưu episode") }
function upsertEpisode(ep: Episode) { const idx = episodes.value.findIndex((item) => item.id === ep.id); if (idx >= 0) episodes.value[idx] = ep; else episodes.value.push(ep); episodes.value.sort((a, b) => a.sortOrder - b.sortOrder) }
function deleteEpisode(ep: Episode) { feedback.dialog?.warning({ title: "Xóa episode?", content: ep.title, positiveText: "Xóa", negativeText: "Hủy", onPositiveClick: async () => { await lessonsApi.deleteEpisode(ep.id); episodes.value = episodes.value.filter((item) => item.id !== ep.id); feedback.message?.success("Đã xóa episode") } }) }
async function toggleEpisode(ep: Episode) { upsertEpisode(await lessonsApi.updateEpisode(ep.id, { isPublished: !ep.isPublished })) }
async function reorder() { if (!course.value) return; episodes.value = episodes.value.map((ep, index) => ({ ...ep, sortOrder: index + 1 })); await lessonsApi.reorder(course.value.id, episodes.value.map((ep) => ({ episodeId: ep.id, sortOrder: ep.sortOrder }))); feedback.message?.success("Đã sắp xếp episode") }
async function uploadThumbnail(event: Event) { const input = event.target as HTMLInputElement; const file = input.files?.[0]; if (!course.value || !file) return; uploadProgress.value = 0; await lessonsApi.uploadThumbnail(course.value.id, file, (pct) => { uploadProgress.value = pct }); uploadProgress.value = null; await load(); feedback.message?.success("Đã upload thumbnail") }
async function uploadEpisodeFile(ep: Episode, event: Event) { const input = event.target as HTMLInputElement; const file = input.files?.[0]; if (!file) return; uploadProgress.value = 0; await lessonsApi.uploadEpisodeFile(ep.id, file, (pct) => { uploadProgress.value = pct }); uploadProgress.value = null; feedback.message?.success("Đã upload file") }
onMounted(() => void load())
</script>
<template><div class="page-stack"><div class="page-header"><div><n-button quaternary size="small" @click="router.back()"><template #icon><ArrowLeft :size="16" /></template>Quay lại</n-button><h1 class="page-title">{{ isNew ? 'Tạo khoá học' : 'Sửa khoá học' }}</h1><p v-if="course" class="page-subtitle">Cập nhật {{ fmtDateTime(course.updatedAt) }}</p></div><n-button type="primary" :loading="saving" @click="saveCourse">Lưu</n-button></div><ErrorState v-if="error" :message="error" @retry="load" /><n-card :loading="loading"><n-form label-placement="top"><n-form-item label="Tiêu đề"><n-input v-model:value="form.title" @update:value="syncSlug" /></n-form-item><n-form-item label="Slug"><n-input v-model:value="form.slug" /></n-form-item><n-form-item label="Mô tả"><n-input v-model:value="form.description" type="textarea" /></n-form-item><n-space wrap><n-form-item label="Level"><n-select v-model:value="form.level" :options="levelOptions" style="width: 180px" /></n-form-item><n-form-item label="Category"><n-input v-model:value="form.category" style="width: 240px" /></n-form-item><n-form-item label="Premium"><n-switch v-model:value="form.isPremium" /></n-form-item><n-form-item label="Published"><n-switch v-model:value="form.isPublished" /></n-form-item></n-space></n-form><n-space v-if="course" align="center"><label class="upload-button"><Upload :size="16" />Thumbnail<input type="file" accept="image/*" @change="uploadThumbnail" /></label><n-progress v-if="uploadProgress !== null" type="line" :percentage="uploadProgress" style="width: 220px" /></n-space></n-card><n-card v-if="course" title="Episodes"><template #header-extra><n-button size="small" type="primary" @click="openEpisode()"><template #icon><Plus :size="16" /></template>Episode</n-button></template><draggable v-model="episodes" item-key="id" handle=".drag-handle" @end="reorder"><template #item="{ element }"><div class="episode-row"><GripVertical class="drag-handle" :size="16" /><div class="episode-main"><strong>{{ element.sortOrder }}. {{ element.title }}</strong><span>{{ element.contentType }} · {{ element.fileUrl ? 'có file' : 'chưa có file' }}</span></div><StatusTag :status="element.isPublished" :label="element.isPublished ? 'Published' : 'Draft'" /><n-space><n-button size="small" secondary @click="openEpisode(element)">Sửa</n-button><n-button size="small" secondary @click="toggleEpisode(element)">{{ element.isPublished ? 'Unpublish' : 'Publish' }}</n-button><label class="upload-button small"><Upload :size="14" /><input type="file" @change="uploadEpisodeFile(element, $event)" /></label><n-button size="small" type="error" secondary @click="deleteEpisode(element)"><template #icon><Trash2 :size="14" /></template></n-button></n-space></div></template></draggable></n-card><n-modal v-model:show="episodeModal" preset="card" :title="editingEpisode ? 'Sửa episode' : 'Tạo episode'" style="max-width: 640px"><n-form label-placement="top"><n-form-item label="Tiêu đề"><n-input v-model:value="episodeForm.title" /></n-form-item><n-form-item label="Mô tả"><n-input v-model:value="episodeForm.description" type="textarea" /></n-form-item><n-space><n-form-item label="Loại"><n-select v-model:value="episodeForm.contentType" :options="contentOptions" style="width: 160px" /></n-form-item><n-form-item label="Thứ tự"><n-input-number v-model:value="episodeForm.sortOrder" :min="1" /></n-form-item><n-form-item label="Published"><n-switch v-model:value="episodeForm.isPublished" /></n-form-item></n-space><n-form-item label="Markdown"><n-input v-model:value="episodeForm.markdownBody" type="textarea" :rows="6" /></n-form-item><n-space justify="end"><n-button secondary @click="episodeModal = false">Hủy</n-button><n-button type="primary" @click="saveEpisode">Lưu</n-button></n-space></n-form></n-modal></div></template>
<style scoped>.episode-row{align-items:center;border:1px solid #1d3452;border-radius:8px;display:flex;gap:12px;margin-bottom:8px;padding:10px}.episode-main{display:flex;flex:1;flex-direction:column;min-width:0}.episode-main span{color:#a9b9cf;font-size:12px}.drag-handle{color:#a9b9cf;cursor:grab}.upload-button{align-items:center;border:1px solid #1d3452;border-radius:8px;color:#d7e2f0;cursor:pointer;display:inline-flex;gap:6px;padding:7px 12px}.upload-button.small{height:28px;padding:4px 8px}.upload-button input{display:none}</style>
